oxy_webhelp_navlinks = {"discovery_ad_domains_dc-d30753e49008":{"topics":[{"title":"Adding an AD domain controller","shortdesc":"<p class=\"shortdesc\">Add an Active Directory domain controller as a Windows host to a Rubrik cluster to         start protecting the domain controller.<\/p>","href":"adds\/adding_ad_domain_controller_2.html","attributes":{"data-id":"adding_ad_domain_controller"},"menu":{"hasChildren":false},"tocID":"adding_ad_domain_controller-d30753e49022","topics":[]},{"title":"Deleting an AD domain controller","shortdesc":"<p class=\"shortdesc\">As an <span class=\"ph\">RSC<\/span> user with the required privileges, delete a Active         Directory domain controller from a Rubrik cluster if the domain controller fails and you         want to stop protecting it.<\/p>","href":"adds\/deleting_ad_domain_controller_2.html","attributes":{"data-id":"deleting_ad_domain_controller"},"menu":{"hasChildren":false},"tocID":"deleting_ad_domain_controller-d30753e49033","topics":[]},{"title":"Viewing AD domain controllers","shortdesc":"<p class=\"shortdesc\">As an <span class=\"ph\">RSC<\/span> user with the required privileges, you can view the         registered AD domain controllers. You can also view the domain controllers associated with         a specific AD domain and manage protection by assigning SLA Domains.<\/p>","href":"adds\/viewing_ad_domain_controllers.html","attributes":{"data-id":"viewing_ad_domain_controllers"},"menu":{"hasChildren":false},"tocID":"viewing_ad_domain_controllers-d30753e49047","topics":[]},{"title":"Unregistered AD domain controllers","shortdesc":"<p class=\"shortdesc\">During AD forest discovery, <span class=\"ph\">RSC<\/span> identifies all the domain controllers         in each discovered domain, including domain controllers that are not registered with a         Rubrik cluster. <span class=\"ph\">RSC<\/span> classifies the discovered domain controllers as         registered or unregistered and displays them in separate sub-tabs on the Domain Controllers         page.<\/p>","href":"adds\/unregistered_ad_domain_controllers.html","attributes":{"data-id":"unregistered_ad_domain_controllers"},"menu":{"hasChildren":false},"tocID":"unregistered_ad_domain_controllers-d30753e49061","topics":[]},{"title":"Registering an unregistered AD domain controller","shortdesc":"<p class=\"shortdesc\">To protect an unregistered AD domain controller, install Rubrik Backup Service (RBS)         on the domain controller and add it to a Rubrik cluster as a Windows host. After         registration, <span class=\"ph\">RSC<\/span> moves the domain controller from the Unregistered DCs         sub-tab to the Registered DCs sub-tab and you can assign an SLA Domain.<\/p>","href":"adds\/registering_unregistered_ad_dc.html","attributes":{"data-id":"registering_unregistered_ad_dc"},"menu":{"hasChildren":false},"tocID":"registering_unregistered_ad_dc-d30753e49078","topics":[]}]}};